pageUsage:
// Filter bar = DS inputs (text/dropdown) + secondary Filtrar button + 2 icon buttons.
// See Inputs and Buttons sections for individual component patterns.

// Container wrapping filter bar + table:
<div style="border-radius:8px;border:1px solid var(--n4);background:#fff;
  padding:20px;display:flex;flex-direction:column;gap:20px">

  <!-- Filter row -->
  <div style="display:flex;align-items:center;gap:8px">
    [text inputs with flex:1]
    [dt-drop-wrap dropdowns with flex:1]

    <!-- Filtrar — secondary button tokens -->
    <button style="height:32px;padding:0 16px;border-radius:50px;
      font:700 14px/1 var(--font-sans);background:#fff;color:#4B82FA;
      border:1px solid #1F60ED;cursor:pointer;display:inline-flex;
      align-items:center;gap:5px;box-sizing:border-box;flex-shrink:0"
      onmouseenter="this.style.background='#EDF5FF'"
      onmouseleave="this.style.background='#fff'"
      onmousedown="this.style.background='#D1E0FF'"
      onmouseup="this.style.background='#EDF5FF'">Filtrar</button>

    <!-- filter--add: B6 -->
    <button style="width:32px;height:32px;border:1px solid var(--b6);border-radius:4px;
      background:#fff;display:inline-flex;align-items:center;justify-content:center;
      cursor:pointer;padding:0;box-sizing:border-box;flex-shrink:0">
      \${iconSvg('filter--add', 24, 'var(--b6)')}
    </button>

    <!-- filter--reset: R6 -->
    <button style="width:32px;height:32px;border:1px solid var(--r6);border-radius:4px;
      background:#fff;display:inline-flex;align-items:center;justify-content:center;
      cursor:pointer;padding:0;box-sizing:border-box;flex-shrink:0">
      \${iconSvg('filter--reset', 24, 'var(--r6)')}
    </button>
  </div>

  \${tblDemoTable(data.scrollDemo || {})}
</div>
